class Node:
    def __init__(self, x: int, nxt=None, rand=None):
        self.val = x
        self.next = nxt
        self.random = rand

class Solution:
    def copyRandomList(self, head):
        if not head:
            return None
        m: dict = {}
        cur = head
        while cur:
            m[cur] = Node(cur.val)
            cur = cur.next
        cur = head
        while cur:
            m[cur].next = m.get(cur.next)
            m[cur].random = m.get(cur.random)
            cur = cur.next
        return m[head]
